const express = require('express');
const axios = require('axios');
const crypto = require('crypto');

const app = express();
app.use(express.json());

// Secure API key storage (in production, use environment variables or secure vault)
const VALID_API_KEYS = new Set([
  process.env.API_KEY_1,
  process.env.API_KEY_2,
  process.env.API_KEY_3
].filter(Boolean));

// Backend service mappings
const SERVICE_ROUTES = {
  '/users': process.env.USER_SERVICE_URL || 'http://localhost:3001',
  '/orders': process.env.ORDER_SERVICE_URL || 'http://localhost:3002',
  '/products': process.env.PRODUCT_SERVICE_URL || 'http://localhost:3003'
};

// Secure logging function that masks sensitive data
function secureLog(req, apiKeyHash, status, message) {
  const logEntry = {
    timestamp: new Date().toISOString(),
    method: req.method,
    path: req.path,
    ip: req.ip,
    apiKeyHash: apiKeyHash,
    status: status,
    message: message,
    userAgent: req.get('user-agent')
  };
  console.log(JSON.stringify(logEntry));
}

// Hash API key for secure logging
function hashApiKey(apiKey) {
  if (!apiKey) return 'none';
  return crypto.createHash('sha256').update(apiKey).digest('hex').substring(0, 16);
}

// API Key authentication middleware
function authenticateApiKey(req, res, next) {
  const apiKey = req.query.api_key;
  const apiKeyHash = hashApiKey(apiKey);
  
  if (!apiKey) {
    secureLog(req, 'none', 401, 'Missing API key');
    return res.status(401).json({ error: 'API key is required' });
  }
  
  if (!VALID_API_KEYS.has(apiKey)) {
    secureLog(req, apiKeyHash, 403, 'Invalid API key');
    return res.status(403).json({ error: 'Invalid API key' });
  }
  
  // Store hashed version for logging
  req.apiKeyHash = apiKeyHash;
  req.validatedApiKey = apiKey;
  
  secureLog(req, apiKeyHash, 200, 'Authentication successful');
  next();
}

// Rate limiting per API key (simple in-memory implementation)
const rateLimitMap = new Map();
const RATE_LIMIT_WINDOW = 60000; // 1 minute
const MAX_REQUESTS = 100;

function rateLimiter(req, res, next) {
  const apiKeyHash = req.apiKeyHash;
  const now = Date.now();
  
  if (!rateLimitMap.has(apiKeyHash)) {
    rateLimitMap.set(apiKeyHash, { count: 1, resetTime: now + RATE_LIMIT_WINDOW });
    return next();
  }
  
  const limitData = rateLimitMap.get(apiKeyHash);
  
  if (now > limitData.resetTime) {
    limitData.count = 1;
    limitData.resetTime = now + RATE_LIMIT_WINDOW;
    return next();
  }
  
  if (limitData.count >= MAX_REQUESTS) {
    secureLog(req, apiKeyHash, 429, 'Rate limit exceeded');
    return res.status(429).json({ error: 'Rate limit exceeded' });
  }
  
  limitData.count++;
  next();
}

// Gateway proxy handler
async function proxyRequest(req, res) {
  const servicePath = Object.keys(SERVICE_ROUTES).find(route => req.path.startsWith(route));
  
  if (!servicePath) {
    secureLog(req, req.apiKeyHash, 404, 'Service not found');
    return res.status(404).json({ error: 'Service not found' });
  }
  
  const backendUrl = SERVICE_ROUTES[servicePath];
  const targetPath = req.path.replace(servicePath, '');
  const fullUrl = `${backendUrl}${targetPath}`;
  
  try {
    // Remove api_key from query params before forwarding
    const forwardQuery = { ...req.query };
    delete forwardQuery.api_key;
    
    const response = await axios({
      method: req.method,
      url: fullUrl,
      headers: {
        'X-API-Key': req.validatedApiKey,
        'X-Forwarded-For': req.ip,
        'X-Original-URI': req.originalUrl,
        'Content-Type': req.get('content-type') || 'application/json'
      },
      params: forwardQuery,
      data: req.body,
      timeout: 30000,
      validateStatus: () => true
    });
    
    secureLog(req, req.apiKeyHash, response.status, `Proxied to ${servicePath}`);
    
    // Forward response headers (excluding sensitive ones)
    const safeHeaders = ['content-type', 'content-length', 'cache-control'];
    safeHeaders.forEach(header => {
      if (response.headers[header]) {
        res.set(header, response.headers[header]);
      }
    });
    
    res.status(response.status).json(response.data);
  } catch (error) {
    secureLog(req, req.apiKeyHash, 502, `Backend error: ${error.message}`);
    res.status(502).json({ error: 'Backend service unavailable' });
  }
}

// Apply middleware and routes
app.use(authenticateApiKey);
app.use(rateLimiter);
app.all('*', proxyRequest);

// Error handler
app.use((err, req, res, next) => {
  const apiKeyHash = req.apiKeyHash || 'none';
  secureLog(req, apiKeyHash, 500, `Internal error: ${err.message}`);
  res.status(500).json({ error: 'Internal server error' });
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Secure API Gateway running on port ${PORT}`);
});

